def getParallelCourses(n,courses):

    adj = collections.defaultdict(list)
    inbound = collections.defaultdict(int)
    for u, v in courses:
        adj[u].append(v)
        adj[v].append(u)
        if inbound.get(u, None) == None:
            inbound[u] = 0
        inbound[v] += 1


    queue = collections.deque()
    for k, v in inbound.items():
        if v == 0:
            queue.append(k)
    total = 0

    while queue:
        qCount = len(queue)
        for _ in range(qCount):
            c = queue.popleft()
            for nei in adj[c]:
                inbound[nei] -= 1
                if inbound[nei] == 0:
                    queue.append(nei)
        total += 1
    return total

import java.util.*;

public class CourseScheduler {
    public static int minimumNumSemesters(int K, int[][] prerequisites) {
        Map<Integer, Set<Integer>> pre = new HashMap<>();
        Map<Integer, Set<Integer>> suc = new HashMap<>();

        for (int i = 0; i < K; i++) {
            pre.put(i, new HashSet<Integer>());
            suc.put(i, new HashSet<Integer>());
        }

        for (int[] prerequisite : prerequisites) {
            int a = prerequisite[0];
            int b = prerequisite[1];
            pre.get(a).add(b);
            suc.get(b).add(a);
        }

        Set<Integer> free = new HashSet<>();
        for (int i = 0; i < K; i++) {
            if (!pre.containsKey(i) || pre.get(i).isEmpty()) {
                free.add(i);
            }
        }

        int[] res = new int[K];
        for (int c : free) {
            res[c] = 1;
        }

        List<Integer> order = new ArrayList<>();
        while (!free.isEmpty()) {
            int a = free.iterator().next();
            free.remove(a);
            order.add(a);
            for (int b : suc.get(a)) {
                pre.get(b).remove(a);
                res[b] = Math.max(res[b], res[a] + 1);
                if (pre.get(b).isEmpty()) {
                    free.add(b);
                }
            }
        }

        if (order.size() != K) {
            throw new IllegalStateException("Not possible to complete all courses");
        }

        int maxSemesters = 0;
        for (int semesters : res) {
            maxSemesters = Math.max(maxSemesters, semesters);
        }

        return maxSemesters;
    }

    public static void main(String[] args) {
        try {
            System.out.println("Example 1: " + minimumNumSemesters(3, new int[][]{{1, 0}, {1, 2}}));
            System.out.println("Example 2: " + minimumNumSemesters(2, new int[][]{{0, 1}, {1, 0}}));
        } catch (IllegalStateException e) {
            System.out.println(e.getMessage());
        }
    }
