def parallelCourses(numOfCourses, dependencies):
    graph = {}
    for prep, course in dependencies:
        if not course in graph:
            graph[course] = set()
        if not prep in graph:
            graph[prep] = set()
        graph[course].add(prep)

    output = ''
    visited = {}
    # Topological sort
    for course in graph:
        if course in visited:
            continue
        stack = [course]
        while len(stack) > 0:
            cur = stack[-1]
            deps = graph[cur]
            found = False
            for dep in deps:
                if not dep in visited:
                    if dep in stack:
                        # Cycle found
                        return "Not possible"
                    stack.append(dep)
                    found = True
                    break
            if not found:
                cur = stack.pop(-1)
                visited[cur] = None
                output += '%d->' % cur
    return output[:-2]

